import { Link, useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext"
import { useState } from "react";
import { isNotEmpty, isValidMobile } from "../utils/validations";

export default function Signup() {
  const { user, signUp, sendOTP } = useAuth();
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [mobile, setMobile] = useState('');
  const [otp, setOtp] = useState('');
  const [error, setError] = useState('');

  if(user) {
    navigate('/view');
  }

  const handleSendOTP = async (e) => {
    e.preventDefault();
    if(!isNotEmpty(mobile) || !isValidMobile(mobile)) {
      setError('Please enter a valid mobile number')
      return;
    }
    const success = await sendOTP(mobile);
    if(success) {
      setStep(2);
      setError('');
    } else {
      setError('Failed to send OTP');
    }
  }

  const handleVerifyOTP = async (e) => {
    e.preventDefault();
    if(!isNotEmpty(otp)) {
      setError('Please enter OTP')
      return;
    }
    const result = await signUp(mobile, otp);
    if(result.success) {
      navigate('/view')
    } else {
      setError(result.message)
    }
  }

  return (
    <div className="panel login-panel">
      <h2>Sign Up</h2>
      {step === 1 ? (
        <form onSubmit={handleSendOTP} className="content-form">
          <div className="form-group">
            <label htmlFor="signup-mobile">Mobile Number:</label>
            <input
              id="signup-mobile"
              type="text"
              placeholder="Enter mobile number"
              value={mobile}
              onChange={(e) => setMobile(e.target.value)}
            />
          </div>
          {error && <div className="error">{error}</div>}
          <button className="btn" type="submit">
            Send OTP
          </button>
          <p>
            Already have an account? <Link to="/login">Log in</Link>
          </p>
        </form>
      ) : (
        <form onSubmit={handleVerifyOTP} className="content-form">
          <div className="form-group">
            <label htmlFor="signup-otp">OTP:</label>
            <input
              id="signup-otp"
              type="text"
              placeholder="Enter OTP"
              value={otp}
              onChange={(e) => setOtp(e.target.value)}
            />
          </div>
          {error && <div className="error">{error}</div>}
          <button className="btn" type="submit">
            Verify OTP
          </button>
          <p>
            <button type="button" onClick={() => setStep(1)}>Back</button>
          </p>
        </form>
      )}
    </div>
  )
}
